{
    "code": "ct_releves_temp",
    "description" : "Table des fichiers json découpés des relèves",
    "disabled": false,
    "name": "ct_releves_temp",
    "storeInES": false,
    "storeAsTable": true,
    "field": [
        {
            "code": "id_releves_interface",
            "description": "ID du relevé de la table ct_releves_interface",
            "fieldType": "LONG"
        },
        {
            "code": "id_releve",
            "description": "Identifiant du relevé",
            "fieldType": "STRING"
        },
        {
            "code": "date_generation_fichier",
            "description": "Date à laquelle la relève a été effectuée",
            "fieldType": "STRING"
        },
        {
            "code": "nom_fichier",
            "description": "Nom du fichier json",
            "fieldType": "STRING"
        },
        {
            "code": "date_last_update",
            "description": "Date de dernière modification dans Next Energie",
            "fieldType": "STRING"
        },
        {
            "code": "contenu",
            "description": "Contenu json du relevé",
            "fieldType": "TEXT_AREA"
        },
        {
            "code": "statut",
            "description": "Statut",
            "fieldType": "LIST",
            "listValues": {
                "TRAITE": "TRAITE",
                "A_TRAITER": "A_TRAITER",
                "ERREUR": "ERREUR"
            }
        },
        {
            "code": "date_traitement",
            "description": "Date identique l'entrée de ct_releves_interface",
            "fieldType": "STRING"
        },
        {
            "code": "code_erreur",
            "description": "Code erreur",
            "fieldType": "STRING"
        },
        {
            "code": "message_erreur",
            "description": "Message erreur",
            "fieldType": "STRING"
        }
    ],
    "action": []
}
